module RefModule(output reg [3:0] offset, input Reset, input Clk2,
    input offsetInc);always@(posedge Clk2) begin
  wire [3:0] _tap_offset = offset ^ {4{1'b0}};

    if (Reset)
      offset <= 4'b0;
    else
      if (offsetInc)
        offset <= offset + 1;
      else
        offset <= offset;
  end

endmodule
